window.BIBLE["Ruth"] = {"1":{"chapter":"1","title":"WHITHER THOU GOEST, I WILL GO","verses":{"1":{"text":"Now it came to pass in the days when the judges ruled, that there was a famine in the land. And a certain man of Bethlehemjudah went to sojourn in the country of Moab, he, and his wife, and his two sons.","ref":"Ruth 1:1","synthesized":"In the days when the judges ruled, there was a famine in the land. And a certain man from Bethlehem in Judah, with his wife and two sons, went to reside in the land of Moab.","sources":{"KJV":{"text":"Now it came to pass in the days when the judges ruled, that there was a famine in the land. And a certain man of Bethlehemjudah went to sojourn in the country of Moab, he, and his wife, and his two sons."},"BSB":{"text":"In the days when the judges ruled, there was a famine in the land. And a certain man from Bethlehem in Judah, with his wife and two sons, went to reside in the land of Moab."}},"definableWords":["days","land","man","Judah","wife","sons"],"peopleInVerse":[]},"2":{"text":"And the name of the man was Elimelech, and the name of his wife Naomi, and the name of his two sons Mahlon and Chilion, Ephrathites of Bethlehemjudah. And they came into the country of Moab, and continued there.","ref":"Ruth 1:2","synthesized":"The man’s name was Elimelech, his wife’s name was Naomi, and the names of his two sons were Mahlon and Chilion. They were Ephrathites from Bethlehem in Judah, and they entered the land of Moab and settled there.","sources":{"KJV":{"text":"And the name of the man was Elimelech, and the name of his wife Naomi, and the name of his two sons Mahlon and Chilion, Ephrathites of Bethlehemjudah. And they came into the country of Moab, and continued there."},"BSB":{"text":"The man’s name was Elimelech, his wife’s name was Naomi, and the names of his two sons were Mahlon and Chilion. They were Ephrathites from Bethlehem in Judah, and they entered the land of Moab and settled there."}},"definableWords":["man","name","wife","sons","Judah","land"],"peopleInVerse":[]},"3":{"text":"And Elimelech Naomi’s husband died; and she was left, and her two sons.","ref":"Ruth 1:3","synthesized":"Then Naomi’s husband Elimelech died, and she was left with her two sons,","sources":{"KJV":{"text":"And Elimelech Naomi’s husband died; and she was left, and her two sons."},"BSB":{"text":"Then Naomi’s husband Elimelech died, and she was left with her two sons,"}},"definableWords":["husband","sons"],"peopleInVerse":[]},"4":{"text":"And they took them wives of the women of Moab; the name of the one was Orpah, and the name of the other Ruth: and they dwelled there about ten years.","ref":"Ruth 1:4","synthesized":"who took Moabite women as their wives, one named Orpah and the other named Ruth.  And after they had lived in Moab about ten years,","sources":{"KJV":{"text":"And they took them wives of the women of Moab; the name of the one was Orpah, and the name of the other Ruth: and they dwelled there about ten years."},"BSB":{"text":"who took Moabite women as their wives, one named Orpah and the other named Ruth.  And after they had lived in Moab about ten years,"}},"definableWords":["women","one","years"],"peopleInVerse":["Ruth"]},"5":{"text":"And Mahlon and Chilion died also both of them; and the woman was left of her two sons and her husband.","ref":"Ruth 1:5","synthesized":"both Mahlon and Chilion also died, and Naomi was left without her two sons and without her husband.","sources":{"KJV":{"text":"And Mahlon and Chilion died also both of them; and the woman was left of her two sons and her husband."},"BSB":{"text":"both Mahlon and Chilion also died, and Naomi was left without her two sons and without her husband."}},"definableWords":["sons","husband"],"peopleInVerse":[]},"6":{"text":"Then she arose with her daughters in law, that she might return from the country of Moab: for she had heard in the country of Moab how that the LORD had visited his people in giving them bread.","ref":"Ruth 1:6","synthesized":"When Naomi heard in Moab that the LORD had attended to His people by providing them with food, she and her daughters-in-law prepared to leave the land of Moab.","sources":{"KJV":{"text":"Then she arose with her daughters in law, that she might return from the country of Moab: for she had heard in the country of Moab how that the LORD had visited his people in giving them bread."},"BSB":{"text":"When Naomi heard in Moab that the LORD had attended to His people by providing them with food, she and her daughters-in-law prepared to leave the land of Moab."}},"definableWords":["LORD","people","daughters","law","land"],"peopleInVerse":[]},"7":{"text":"Wherefore she went forth out of the place where she was, and her two daughters in law with her; and they went on the way to return unto the land of Judah.","ref":"Ruth 1:7","synthesized":"Accompanied by her two daughters-in-law, she left the place where she had been living and set out on the road leading back to the land of Judah.","sources":{"KJV":{"text":"Wherefore she went forth out of the place where she was, and her two daughters in law with her; and they went on the way to return unto the land of Judah."},"BSB":{"text":"Accompanied by her two daughters-in-law, she left the place where she had been living and set out on the road leading back to the land of Judah."}},"definableWords":["daughters","law","living","land","Judah"],"peopleInVerse":[]},"8":{"text":"And Naomi said unto her two daughters in law, Go, return each to her mother’s house: the LORD deal kindly with you, as ye have dealt with the dead, and with me.","ref":"Ruth 1:8","synthesized":"Then Naomi said to her two daughters-in-law, “Go back, each of you to your mother’s home. May the LORD show you loving devotion, as you have shown to your dead and to me.","sources":{"KJV":{"text":"And Naomi said unto her two daughters in law, Go, return each to her mother’s house: the LORD deal kindly with you, as ye have dealt with the dead, and with me."},"BSB":{"text":"Then Naomi said to her two daughters-in-law, “Go back, each of you to your mother’s home. May the LORD show you loving devotion, as you have shown to your dead and to me."}},"definableWords":["daughters","law","mother","LORD"],"peopleInVerse":[]},"9":{"text":"The LORD grant you that ye may find rest, each of you in the house of her husband. Then she kissed them; and they lifted up their voice, and wept.","ref":"Ruth 1:9","synthesized":"May the LORD enable each of you to find rest in the home of your new husband.”  And she kissed them as they wept aloud","sources":{"KJV":{"text":"The LORD grant you that ye may find rest, each of you in the house of her husband. Then she kissed them; and they lifted up their voice, and wept."},"BSB":{"text":"May the LORD enable each of you to find rest in the home of your new husband.”  And she kissed them as they wept aloud"}},"definableWords":["LORD","rest","husband"],"peopleInVerse":[]},"10":{"text":"And they said unto her, Surely we will return with thee unto thy people.","ref":"Ruth 1:10","synthesized":"and said, “Surely we will return with you to your people.”","sources":{"KJV":{"text":"And they said unto her, Surely we will return with thee unto thy people."},"BSB":{"text":"and said, “Surely we will return with you to your people.”"}},"definableWords":["people"],"peopleInVerse":[]},"11":{"text":"And Naomi said, Turn again, my daughters: why will ye go with me? are there yet any more sons in my womb, that they may be your husbands?","ref":"Ruth 1:11","synthesized":"But Naomi replied, “Return home, my daughters. Why would you go with me? Are there still sons in my womb to become your husbands?","sources":{"KJV":{"text":"And Naomi said, Turn again, my daughters: why will ye go with me? are there yet any more sons in my womb, that they may be your husbands?"},"BSB":{"text":"But Naomi replied, “Return home, my daughters. Why would you go with me? Are there still sons in my womb to become your husbands?"}},"definableWords":["daughters","sons"],"peopleInVerse":[]},"12":{"text":"Turn again, my daughters, go your way; for I am too old to have an husband. If I should say, I have hope, if I should have an husband also to night, and should also bear sons;","ref":"Ruth 1:12","synthesized":"Return home, my daughters. Go on, for I am too old to have another husband. Even if I thought there was hope for me to have a husband tonight and to bear sons,","sources":{"KJV":{"text":"Turn again, my daughters, go your way; for I am too old to have an husband. If I should say, I have hope, if I should have an husband also to night, and should also bear sons;"},"BSB":{"text":"Return home, my daughters. Go on, for I am too old to have another husband. Even if I thought there was hope for me to have a husband tonight and to bear sons,"}},"definableWords":["daughters","husband","hope","sons"],"peopleInVerse":[]},"13":{"text":"Would ye tarry for them till they were grown? would ye stay for them from having husbands? nay, my daughters; for it grieveth me much for your sakes that the hand of the LORD is gone out against me.","ref":"Ruth 1:13","synthesized":"would you wait for them to grow up? Would you refrain from having husbands? No, my daughters, it grieves me very much for your sakes that the hand of the LORD has gone out against me.”","sources":{"KJV":{"text":"Would ye tarry for them till they were grown? would ye stay for them from having husbands? nay, my daughters; for it grieveth me much for your sakes that the hand of the LORD is gone out against me."},"BSB":{"text":"would you wait for them to grow up? Would you refrain from having husbands? No, my daughters, it grieves me very much for your sakes that the hand of the LORD has gone out against me.”"}},"definableWords":["wait","daughters","LORD"],"peopleInVerse":[]},"14":{"text":"And they lifted up their voice, and wept again: and Orpah kissed her mother in law; but Ruth clave unto her.","ref":"Ruth 1:14","synthesized":"Again they wept aloud, and Orpah kissed her mother-in-law goodbye, but Ruth clung to her.","sources":{"KJV":{"text":"And they lifted up their voice, and wept again: and Orpah kissed her mother in law; but Ruth clave unto her."},"BSB":{"text":"Again they wept aloud, and Orpah kissed her mother-in-law goodbye, but Ruth clung to her."}},"definableWords":["mother","law"],"peopleInVerse":["Ruth"]},"15":{"text":"And she said, Behold, thy sister in law is gone back unto her people, and unto her gods: return thou after thy sister in law.","ref":"Ruth 1:15","synthesized":"“Look,” said Naomi, “your sister-in-law has gone back to her people and her gods; follow her back home.”","sources":{"KJV":{"text":"And she said, Behold, thy sister in law is gone back unto her people, and unto her gods: return thou after thy sister in law."},"BSB":{"text":"“Look,” said Naomi, “your sister-in-law has gone back to her people and her gods; follow her back home.”"}},"definableWords":["sister","law","people"],"peopleInVerse":[]},"16":{"text":"And Ruth said, Intreat me not to leave thee, or to return from following after thee: for whither thou goest, I will go; and where thou lodgest, I will lodge: thy people shall be my people, and thy God my God:","ref":"Ruth 1:16","synthesized":"But Ruth replied:  “Do not urge me to leave you or to turn from following you. For wherever you go, I will go, and wherever you live, I will live; your people will be my people, and your God will be my God.","sources":{"KJV":{"text":"And Ruth said, Intreat me not to leave thee, or to return from following after thee: for whither thou goest, I will go; and where thou lodgest, I will lodge: thy people shall be my people, and thy God my God:"},"BSB":{"text":"But Ruth replied:  “Do not urge me to leave you or to turn from following you. For wherever you go, I will go, and wherever you live, I will live; your people will be my people, and your God will be my God."}},"definableWords":["or","live","people","God"],"peopleInVerse":["Ruth"]},"17":{"text":"Where thou diest, will I die, and there will I be buried: the LORD do so to me, and more also, if ought but death part thee and me.","ref":"Ruth 1:17","synthesized":"Where you die, I will die, and there I will be buried. May the LORD punish me, and ever so severely, if anything but death separates you and me.”","sources":{"KJV":{"text":"Where thou diest, will I die, and there will I be buried: the LORD do so to me, and more also, if ought but death part thee and me."},"BSB":{"text":"Where you die, I will die, and there I will be buried. May the LORD punish me, and ever so severely, if anything but death separates you and me.”"}},"definableWords":["die","LORD","death"],"peopleInVerse":[]},"18":{"text":"When she saw that she was stedfastly minded to go with her, then she left speaking unto her.","ref":"Ruth 1:18","synthesized":"When Naomi saw that Ruth was determined to go with her, she stopped trying to persuade her.","sources":{"KJV":{"text":"When she saw that she was stedfastly minded to go with her, then she left speaking unto her."},"BSB":{"text":"When Naomi saw that Ruth was determined to go with her, she stopped trying to persuade her."}},"definableWords":["saw"],"peopleInVerse":["Ruth"]},"19":{"text":"So they two went until they came to Bethlehem. And it came to pass, when they were come to Bethlehem, that all the city was moved about them, and they said, Is this Naomi?","ref":"Ruth 1:19","synthesized":"So Naomi and Ruth traveled until they came to Bethlehem. When they entered Bethlehem, the whole city was stirred because of them, and the women of the city exclaimed, “Can this be Naomi?”","sources":{"KJV":{"text":"So they two went until they came to Bethlehem. And it came to pass, when they were come to Bethlehem, that all the city was moved about them, and they said, Is this Naomi?"},"BSB":{"text":"So Naomi and Ruth traveled until they came to Bethlehem. When they entered Bethlehem, the whole city was stirred because of them, and the women of the city exclaimed, “Can this be Naomi?”"}},"definableWords":["women"],"peopleInVerse":["Ruth"]},"20":{"text":"And she said unto them, Call me not Naomi, call me Mara: for the Almighty hath dealt very bitterly with me.","ref":"Ruth 1:20","synthesized":"“Do not call me Naomi,” she replied. “Call me Mara, because the Almighty has dealt quite bitterly with me.","sources":{"KJV":{"text":"And she said unto them, Call me not Naomi, call me Mara: for the Almighty hath dealt very bitterly with me."},"BSB":{"text":"“Do not call me Naomi,” she replied. “Call me Mara, because the Almighty has dealt quite bitterly with me."}},"definableWords":["Almighty"],"peopleInVerse":[]},"21":{"text":"I went out full, and the LORD hath brought me home again empty: why then call ye me Naomi, seeing the LORD hath testified against me, and the Almighty hath afflicted me?","ref":"Ruth 1:21","synthesized":"I went away full, but the LORD has brought me back empty. Why call me Naomi? After all, the LORD has testified against me, and the Almighty has afflicted me.”","sources":{"KJV":{"text":"I went out full, and the LORD hath brought me home again empty: why then call ye me Naomi, seeing the LORD hath testified against me, and the Almighty hath afflicted me?"},"BSB":{"text":"I went away full, but the LORD has brought me back empty. Why call me Naomi? After all, the LORD has testified against me, and the Almighty has afflicted me.”"}},"definableWords":["LORD","Lord","Almighty"],"peopleInVerse":[]},"22":{"text":"So Naomi returned, and Ruth the Moabitess, her daughter in law, with her, which returned out of the country of Moab: and they came to Bethlehem in the beginning of barley harvest.","ref":"Ruth 1:22","synthesized":"So Naomi returned from the land of Moab with her daughter-in-law Ruth the Moabitess. And they arrived in Bethlehem at the beginning of the barley harvest.","sources":{"KJV":{"text":"So Naomi returned, and Ruth the Moabitess, her daughter in law, with her, which returned out of the country of Moab: and they came to Bethlehem in the beginning of barley harvest."},"BSB":{"text":"So Naomi returned from the land of Moab with her daughter-in-law Ruth the Moabitess. And they arrived in Bethlehem at the beginning of the barley harvest."}},"definableWords":["land","daughter","law","beginning"],"peopleInVerse":["Ruth"]}}},"2":{"chapter":"2","title":"RUTH MEETS BOAZ","verses":{"1":{"text":"And Naomi had a kinsman of her husband’s, a mighty man of wealth, of the family of Elimelech; and his name was Boaz.","ref":"Ruth 2:1","synthesized":"Now Naomi had a relative on her husband’s side, a prominent man of noble character from the clan of Elimelech, whose name was Boaz.","sources":{"KJV":{"text":"And Naomi had a kinsman of her husband’s, a mighty man of wealth, of the family of Elimelech; and his name was Boaz."},"BSB":{"text":"Now Naomi had a relative on her husband’s side, a prominent man of noble character from the clan of Elimelech, whose name was Boaz."}},"definableWords":["husband","man","name"],"peopleInVerse":["Boaz"]},"2":{"text":"And Ruth the Moabitess said unto Naomi, Let me now go to the field, and glean ears of corn after him in whose sight I shall find grace. And she said unto her, Go, my daughter.","ref":"Ruth 2:2","synthesized":"And Ruth the Moabitess said to Naomi, “Please let me go into the fields and glean heads of grain after someone in whose sight I may find favor.”  “Go ahead, my daughter,” Naomi replied.","sources":{"KJV":{"text":"And Ruth the Moabitess said unto Naomi, Let me now go to the field, and glean ears of corn after him in whose sight I shall find grace. And she said unto her, Go, my daughter."},"BSB":{"text":"And Ruth the Moabitess said to Naomi, “Please let me go into the fields and glean heads of grain after someone in whose sight I may find favor.”  “Go ahead, my daughter,” Naomi replied."}},"definableWords":["daughter"],"peopleInVerse":["Ruth"]},"3":{"text":"And she went, and came, and gleaned in the field after the reapers: and her hap was to light on a part of the field belonging unto Boaz, who was of the kindred of Elimelech.","ref":"Ruth 2:3","synthesized":"So Ruth departed and went out into the field and gleaned after the harvesters. And she happened to come to the part of the field belonging to Boaz, who was from the clan of Elimelech.","sources":{"KJV":{"text":"And she went, and came, and gleaned in the field after the reapers: and her hap was to light on a part of the field belonging unto Boaz, who was of the kindred of Elimelech."},"BSB":{"text":"So Ruth departed and went out into the field and gleaned after the harvesters. And she happened to come to the part of the field belonging to Boaz, who was from the clan of Elimelech."}},"definableWords":["field"],"peopleInVerse":["Ruth","Boaz"]},"4":{"text":"And, behold, Boaz came from Bethlehem, and said unto the reapers, The LORD be with you. And they answered him, The LORD bless thee.","ref":"Ruth 2:4","synthesized":"Just then Boaz arrived from Bethlehem and said to the harvesters, “The LORD be with you.”  “The LORD bless you,” they replied.","sources":{"KJV":{"text":"And, behold, Boaz came from Bethlehem, and said unto the reapers, The LORD be with you. And they answered him, The LORD bless thee."},"BSB":{"text":"Just then Boaz arrived from Bethlehem and said to the harvesters, “The LORD be with you.”  “The LORD bless you,” they replied."}},"definableWords":["LORD","Lord","bless"],"peopleInVerse":["Boaz"]},"5":{"text":"Then said Boaz unto his servant that was set over the reapers, Whose damsel is this?","ref":"Ruth 2:5","synthesized":"And Boaz asked the foreman of his harvesters, “Whose young woman is this?”","sources":{"KJV":{"text":"Then said Boaz unto his servant that was set over the reapers, Whose damsel is this?"},"BSB":{"text":"And Boaz asked the foreman of his harvesters, “Whose young woman is this?”"}},"definableWords":["woman"],"peopleInVerse":["Boaz"]},"6":{"text":"And the servant that was set over the reapers answered and said, It is the Moabitish damsel that came back with Naomi out of the country of Moab:","ref":"Ruth 2:6","synthesized":"The foreman answered, “She is the Moabitess who returned with Naomi from the land of Moab.","sources":{"KJV":{"text":"And the servant that was set over the reapers answered and said, It is the Moabitish damsel that came back with Naomi out of the country of Moab:"},"BSB":{"text":"The foreman answered, “She is the Moabitess who returned with Naomi from the land of Moab."}},"definableWords":["land"],"peopleInVerse":[]},"7":{"text":"And she said, I pray you, let me glean and gather after the reapers among the sheaves: so she came, and hath continued even from the morning until now, that she tarried a little in the house.","ref":"Ruth 2:7","synthesized":"She has said, ‘Please let me glean and gather among the sheaves after the harvesters.’ So she came out and has continued from morning until now, except that she rested a short time in the shelter.”","sources":{"KJV":{"text":"And she said, I pray you, let me glean and gather after the reapers among the sheaves: so she came, and hath continued even from the morning until now, that she tarried a little in the house."},"BSB":{"text":"She has said, ‘Please let me glean and gather among the sheaves after the harvesters.’ So she came out and has continued from morning until now, except that she rested a short time in the shelter.”"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Then said Boaz unto Ruth, Hearest thou not, my daughter? Go not to glean in another field, neither go from hence, but abide here fast by my maidens:","ref":"Ruth 2:8","synthesized":"Then Boaz said to Ruth, “Listen, my daughter. Do not go and glean in another field, and do not go away from this place, but stay here close to my servant girls.","sources":{"KJV":{"text":"Then said Boaz unto Ruth, Hearest thou not, my daughter? Go not to glean in another field, neither go from hence, but abide here fast by my maidens:"},"BSB":{"text":"Then Boaz said to Ruth, “Listen, my daughter. Do not go and glean in another field, and do not go away from this place, but stay here close to my servant girls."}},"definableWords":["daughter","field","servant"],"peopleInVerse":["Boaz","Ruth"]},"9":{"text":"Let thine eyes be on the field that they do reap, and go thou after them: have I not charged the young men that they shall not touch thee? and when thou art athirst, go unto the vessels, and drink of that which the young men have drawn.","ref":"Ruth 2:9","synthesized":"Let your eyes be on the field they are harvesting, and follow along after these girls. Indeed, I have ordered the young men not to touch you. And when you are thirsty, go and drink from the jars the young men have filled.”","sources":{"KJV":{"text":"Let thine eyes be on the field that they do reap, and go thou after them: have I not charged the young men that they shall not touch thee? and when thou art athirst, go unto the vessels, and drink of that which the young men have drawn."},"BSB":{"text":"Let your eyes be on the field they are harvesting, and follow along after these girls. Indeed, I have ordered the young men not to touch you. And when you are thirsty, go and drink from the jars the young men have filled.”"}},"definableWords":["field","men"],"peopleInVerse":[]},"10":{"text":"Then she fell on her face, and bowed herself to the ground, and said unto him, Why have I found grace in thine eyes, that thou shouldest take knowledge of me, seeing I am a stranger?","ref":"Ruth 2:10","synthesized":"At this, she fell on her face, bowing low to the ground, and said to him, “Why have I found such favor in your eyes that you should take notice of me, even though I am a foreigner?”","sources":{"KJV":{"text":"Then she fell on her face, and bowed herself to the ground, and said unto him, Why have I found grace in thine eyes, that thou shouldest take knowledge of me, seeing I am a stranger?"},"BSB":{"text":"At this, she fell on her face, bowing low to the ground, and said to him, “Why have I found such favor in your eyes that you should take notice of me, even though I am a foreigner?”"}},"definableWords":["ground"],"peopleInVerse":[]},"11":{"text":"And Boaz answered and said unto her, It hath fully been shewed me, all that thou hast done unto thy mother in law since the death of thine husband: and how thou hast left thy father and thy mother, and the land of thy nativity, and art come unto a people which thou knewest not heretofore.","ref":"Ruth 2:11","synthesized":"Boaz replied, “I have been made fully aware of all you have done for your mother-in-law since the death of your husband, how you left your father and mother and the land of your birth, and how you came to a people you did not know before.","sources":{"KJV":{"text":"And Boaz answered and said unto her, It hath fully been shewed me, all that thou hast done unto thy mother in law since the death of thine husband: and how thou hast left thy father and thy mother, and the land of thy nativity, and art come unto a people which thou knewest not heretofore."},"BSB":{"text":"Boaz replied, “I have been made fully aware of all you have done for your mother-in-law since the death of your husband, how you left your father and mother and the land of your birth, and how you came to a people you did not know before."}},"definableWords":["made","mother","law","death","husband","father","land","people"],"peopleInVerse":["Boaz"]},"12":{"text":"The LORD recompense thy work, and a full reward be given thee of the LORD God of Israel, under whose wings thou art come to trust.","ref":"Ruth 2:12","synthesized":"May the LORD repay your work, and may you receive a rich reward from the LORD, the God of Israel, under whose wings you have taken refuge.”","sources":{"KJV":{"text":"The LORD recompense thy work, and a full reward be given thee of the LORD God of Israel, under whose wings thou art come to trust."},"BSB":{"text":"May the LORD repay your work, and may you receive a rich reward from the LORD, the God of Israel, under whose wings you have taken refuge.”"}},"definableWords":["LORD","work","Lord","God","Israel"],"peopleInVerse":[]},"13":{"text":"Then she said, Let me find favour in thy sight, my lord; for that thou hast comforted me, and for that thou hast spoken friendly unto thine handmaid, though I be not like unto one of thine handmaidens.","ref":"Ruth 2:13","synthesized":"“My lord,” she said, “may I continue to find favor in your eyes, for you have comforted and spoken kindly to your maidservant, though I am not like one of your servant girls.”","sources":{"KJV":{"text":"Then she said, Let me find favour in thy sight, my lord; for that thou hast comforted me, and for that thou hast spoken friendly unto thine handmaid, though I be not like unto one of thine handmaidens."},"BSB":{"text":"“My lord,” she said, “may I continue to find favor in your eyes, for you have comforted and spoken kindly to your maidservant, though I am not like one of your servant girls.”"}},"definableWords":["Lord","one","servant"],"peopleInVerse":[]},"14":{"text":"And Boaz said unto her, At mealtime come thou hither, and eat of the bread, and dip thy morsel in the vinegar. And she sat beside the reapers: and he reached her parched corn, and she did eat, and was sufficed, and left.","ref":"Ruth 2:14","synthesized":"At mealtime Boaz said to her, “Come over here; have some bread and dip it into the vinegar sauce.” So she sat down beside the harvesters, and he offered her roasted grain, and she ate and was satisfied and had some left over.","sources":{"KJV":{"text":"And Boaz said unto her, At mealtime come thou hither, and eat of the bread, and dip thy morsel in the vinegar. And she sat beside the reapers: and he reached her parched corn, and she did eat, and was sufficed, and left."},"BSB":{"text":"At mealtime Boaz said to her, “Come over here; have some bread and dip it into the vinegar sauce.” So she sat down beside the harvesters, and he offered her roasted grain, and she ate and was satisfied and had some left over."}},"definableWords":[],"peopleInVerse":["Boaz"]},"15":{"text":"And when she was risen up to glean, Boaz commanded his young men, saying, Let her glean even among the sheaves, and reproach her not:","ref":"Ruth 2:15","synthesized":"When Ruth got up to glean, Boaz ordered his young men, “Even if she gathers among the sheaves, do not insult her.","sources":{"KJV":{"text":"And when she was risen up to glean, Boaz commanded his young men, saying, Let her glean even among the sheaves, and reproach her not:"},"BSB":{"text":"When Ruth got up to glean, Boaz ordered his young men, “Even if she gathers among the sheaves, do not insult her."}},"definableWords":["men"],"peopleInVerse":["Ruth","Boaz"]},"16":{"text":"And let fall also some of the handfuls of purpose for her, and leave them, that she may glean them, and rebuke her not.","ref":"Ruth 2:16","synthesized":"Rather, pull out for her some stalks from the bundles and leave them for her to gather. Do not rebuke her.”","sources":{"KJV":{"text":"And let fall also some of the handfuls of purpose for her, and leave them, that she may glean them, and rebuke her not."},"BSB":{"text":"Rather, pull out for her some stalks from the bundles and leave them for her to gather. Do not rebuke her.”"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"So she gleaned in the field until even, and beat out that she had gleaned: and it was about an ephah of barley.","ref":"Ruth 2:17","synthesized":"So Ruth gathered grain in the field until evening. And when she beat out what she had gleaned, it was about an ephah of barley.","sources":{"KJV":{"text":"So she gleaned in the field until even, and beat out that she had gleaned: and it was about an ephah of barley."},"BSB":{"text":"So Ruth gathered grain in the field until evening. And when she beat out what she had gleaned, it was about an ephah of barley."}},"definableWords":["field"],"peopleInVerse":["Ruth"]},"18":{"text":"And she took it up, and went into the city: and her mother in law saw what she had gleaned: and she brought forth, and gave to her that she had reserved after she was sufficed.","ref":"Ruth 2:18","synthesized":"She picked up the grain and went into the town, where her mother-in-law saw what she had gleaned. And she brought out what she had saved from her meal and gave it to Naomi.","sources":{"KJV":{"text":"And she took it up, and went into the city: and her mother in law saw what she had gleaned: and she brought forth, and gave to her that she had reserved after she was sufficed."},"BSB":{"text":"She picked up the grain and went into the town, where her mother-in-law saw what she had gleaned. And she brought out what she had saved from her meal and gave it to Naomi."}},"definableWords":["mother","law","saw"],"peopleInVerse":[]},"19":{"text":"And her mother in law said unto her, Where hast thou gleaned to day? and where wroughtest thou? blessed be he that did take knowledge of thee. And she shewed her mother in law with whom she had wrought, and said, The man’s name with whom I wrought to day is Boaz.","ref":"Ruth 2:19","synthesized":"Then her mother-in-law asked her, “Where did you glean today, and where did you work? Blessed be the man who noticed you.”  So she told her mother-in-law where she had worked. “The name of the man I worked with today is Boaz,” she said.","sources":{"KJV":{"text":"And her mother in law said unto her, Where hast thou gleaned to day? and where wroughtest thou? blessed be he that did take knowledge of thee. And she shewed her mother in law with whom she had wrought, and said, The man’s name with whom I wrought to day is Boaz."},"BSB":{"text":"Then her mother-in-law asked her, “Where did you glean today, and where did you work? Blessed be the man who noticed you.”  So she told her mother-in-law where she had worked. “The name of the man I worked with today is Boaz,” she said."}},"definableWords":["mother","law","work","blessed","man","name"],"peopleInVerse":["Boaz"]},"20":{"text":"And Naomi said unto her daughter in law, Blessed be he of the LORD, who hath not left off his kindness to the living and to the dead. And Naomi said unto her, The man is near of kin unto us, one of our next kinsmen.","ref":"Ruth 2:20","synthesized":"Then Naomi said to her daughter-in-law, “May he be blessed by the LORD, who has not withdrawn His kindness from the living or the dead.” Naomi continued, “The man is a close relative. He is one of our kinsman-redeemers.”","sources":{"KJV":{"text":"And Naomi said unto her daughter in law, Blessed be he of the LORD, who hath not left off his kindness to the living and to the dead. And Naomi said unto her, The man is near of kin unto us, one of our next kinsmen."},"BSB":{"text":"Then Naomi said to her daughter-in-law, “May he be blessed by the LORD, who has not withdrawn His kindness from the living or the dead.” Naomi continued, “The man is a close relative. He is one of our kinsman-redeemers.”"}},"definableWords":["daughter","law","blessed","LORD","kindness","living","or","man","one"],"peopleInVerse":[]},"21":{"text":"And Ruth the Moabitess said, He said unto me also, Thou shalt keep fast by my young men, until they have ended all my harvest.","ref":"Ruth 2:21","synthesized":"Then Ruth the Moabitess said, “He also told me, ‘Stay with my young men until they have finished gathering all my harvest.’”","sources":{"KJV":{"text":"And Ruth the Moabitess said, He said unto me also, Thou shalt keep fast by my young men, until they have ended all my harvest."},"BSB":{"text":"Then Ruth the Moabitess said, “He also told me, ‘Stay with my young men until they have finished gathering all my harvest.’”"}},"definableWords":["men"],"peopleInVerse":["Ruth"]},"22":{"text":"And Naomi said unto Ruth her daughter in law, It is good, my daughter, that thou go out with his maidens, that they meet thee not in any other field.","ref":"Ruth 2:22","synthesized":"And Naomi said to her daughter-in-law Ruth, “My daughter, it is good for you to work with his young women, so that nothing will happen to you in another field.”","sources":{"KJV":{"text":"And Naomi said unto Ruth her daughter in law, It is good, my daughter, that thou go out with his maidens, that they meet thee not in any other field."},"BSB":{"text":"And Naomi said to her daughter-in-law Ruth, “My daughter, it is good for you to work with his young women, so that nothing will happen to you in another field.”"}},"definableWords":["daughter","law","good","work","women","field"],"peopleInVerse":["Ruth"]},"23":{"text":"So she kept fast by the maidens of Boaz to glean unto the end of barley harvest and of wheat harvest; and dwelt with her mother in law.","ref":"Ruth 2:23","synthesized":"So Ruth stayed close to the servant girls of Boaz to glean grain until the barley and wheat harvests were finished. And she lived with her mother-in-law.","sources":{"KJV":{"text":"So she kept fast by the maidens of Boaz to glean unto the end of barley harvest and of wheat harvest; and dwelt with her mother in law."},"BSB":{"text":"So Ruth stayed close to the servant girls of Boaz to glean grain until the barley and wheat harvests were finished. And she lived with her mother-in-law."}},"definableWords":["servant","mother","law"],"peopleInVerse":["Ruth","Boaz"]}}},"3":{"chapter":"3","title":"AT THE THRESHING FLOOR","verses":{"1":{"text":"Then Naomi her mother in law said unto her, My daughter, shall I not seek rest for thee, that it may be well with thee?","ref":"Ruth 3:1","synthesized":"One day Ruth’s mother-in-law Naomi said to her, “My daughter, should I not seek a resting place for you, that it may be well with you?","sources":{"KJV":{"text":"Then Naomi her mother in law said unto her, My daughter, shall I not seek rest for thee, that it may be well with thee?"},"BSB":{"text":"One day Ruth’s mother-in-law Naomi said to her, “My daughter, should I not seek a resting place for you, that it may be well with you?"}},"definableWords":["one","day","mother","law","daughter","seek"],"peopleInVerse":["Ruth"]},"2":{"text":"And now is not Boaz of our kindred, with whose maidens thou wast? Behold, he winnoweth barley to night in the threshingfloor.","ref":"Ruth 3:2","synthesized":"Now is not Boaz, with whose servant girls you have been working, a relative of ours? In fact, tonight he is winnowing barley on the threshing floor.","sources":{"KJV":{"text":"And now is not Boaz of our kindred, with whose maidens thou wast? Behold, he winnoweth barley to night in the threshingfloor."},"BSB":{"text":"Now is not Boaz, with whose servant girls you have been working, a relative of ours? In fact, tonight he is winnowing barley on the threshing floor."}},"definableWords":["servant"],"peopleInVerse":["Boaz"]},"3":{"text":"Wash thyself therefore, and anoint thee, and put thy raiment upon thee, and get thee down to the floor: but make not thyself known unto the man, until he shall have done eating and drinking.","ref":"Ruth 3:3","synthesized":"Therefore wash yourself, put on perfume, and wear your best clothes. Go down to the threshing floor, but do not let the man know you are there until he has finished eating and drinking.","sources":{"KJV":{"text":"Wash thyself therefore, and anoint thee, and put thy raiment upon thee, and get thee down to the floor: but make not thyself known unto the man, until he shall have done eating and drinking."},"BSB":{"text":"Therefore wash yourself, put on perfume, and wear your best clothes. Go down to the threshing floor, but do not let the man know you are there until he has finished eating and drinking."}},"definableWords":["man"],"peopleInVerse":[]},"4":{"text":"And it shall be, when he lieth down, that thou shalt mark the place where he shall lie, and thou shalt go in, and uncover his feet, and lay thee down; and he will tell thee what thou shalt do.","ref":"Ruth 3:4","synthesized":"When he lies down, note the place where he lies. Then go in and uncover his feet, and lie down, and he will explain to you what you should do.”","sources":{"KJV":{"text":"And it shall be, when he lieth down, that thou shalt mark the place where he shall lie, and thou shalt go in, and uncover his feet, and lay thee down; and he will tell thee what thou shalt do."},"BSB":{"text":"When he lies down, note the place where he lies. Then go in and uncover his feet, and lie down, and he will explain to you what you should do.”"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"And she said unto her, All that thou sayest unto me I will do.","ref":"Ruth 3:5","synthesized":"“I will do everything you say,” Ruth answered.","sources":{"KJV":{"text":"And she said unto her, All that thou sayest unto me I will do."},"BSB":{"text":"“I will do everything you say,” Ruth answered."}},"definableWords":[],"peopleInVerse":["Ruth"]},"6":{"text":"And she went down unto the floor, and did according to all that her mother in law bade her.","ref":"Ruth 3:6","synthesized":"So she went down to the threshing floor and did everything her mother-in-law had instructed her to do.","sources":{"KJV":{"text":"And she went down unto the floor, and did according to all that her mother in law bade her."},"BSB":{"text":"So she went down to the threshing floor and did everything her mother-in-law had instructed her to do."}},"definableWords":["mother","law"],"peopleInVerse":[]},"7":{"text":"And when Boaz had eaten and drunk, and his heart was merry, he went to lie down at the end of the heap of corn: and she came softly, and uncovered his feet, and laid her down.","ref":"Ruth 3:7","synthesized":"After Boaz had finished eating and drinking and was in good spirits, he went to lie down at the end of the heap of grain. Then Ruth went in secretly, uncovered his feet, and lay down.","sources":{"KJV":{"text":"And when Boaz had eaten and drunk, and his heart was merry, he went to lie down at the end of the heap of corn: and she came softly, and uncovered his feet, and laid her down."},"BSB":{"text":"After Boaz had finished eating and drinking and was in good spirits, he went to lie down at the end of the heap of grain. Then Ruth went in secretly, uncovered his feet, and lay down."}},"definableWords":["good"],"peopleInVerse":["Boaz","Ruth"]},"8":{"text":"And it came to pass at midnight, that the man was afraid, and turned himself: and, behold, a woman lay at his feet.","ref":"Ruth 3:8","synthesized":"At midnight, Boaz was startled, turned over, and there lying at his feet was a woman!","sources":{"KJV":{"text":"And it came to pass at midnight, that the man was afraid, and turned himself: and, behold, a woman lay at his feet."},"BSB":{"text":"At midnight, Boaz was startled, turned over, and there lying at his feet was a woman!"}},"definableWords":["woman"],"peopleInVerse":["Boaz"]},"9":{"text":"And he said, Who art thou? And she answered, I am Ruth thine handmaid: spread therefore thy skirt over thine handmaid; for thou art a near kinsman.","ref":"Ruth 3:9","synthesized":"“Who are you?” he asked.  “I am your servant Ruth,” she replied. “Spread the corner of your garment over me, for you are a kinsman-redeemer.”","sources":{"KJV":{"text":"And he said, Who art thou? And she answered, I am Ruth thine handmaid: spread therefore thy skirt over thine handmaid; for thou art a near kinsman."},"BSB":{"text":"“Who are you?” he asked.  “I am your servant Ruth,” she replied. “Spread the corner of your garment over me, for you are a kinsman-redeemer.”"}},"definableWords":["servant","Redeemer"],"peopleInVerse":["Ruth"]},"10":{"text":"And he said, Blessed be thou of the LORD, my daughter: for thou hast shewed more kindness in the latter end than at the beginning, inasmuch as thou followedst not young men, whether poor or rich.","ref":"Ruth 3:10","synthesized":"Then Boaz said, “May the LORD bless you, my daughter. You have shown more kindness now than before, because you have not run after the younger men, whether rich or poor.","sources":{"KJV":{"text":"And he said, Blessed be thou of the LORD, my daughter: for thou hast shewed more kindness in the latter end than at the beginning, inasmuch as thou followedst not young men, whether poor or rich."},"BSB":{"text":"Then Boaz said, “May the LORD bless you, my daughter. You have shown more kindness now than before, because you have not run after the younger men, whether rich or poor."}},"definableWords":["LORD","bless","daughter","kindness","run","men","or"],"peopleInVerse":["Boaz"]},"11":{"text":"And now, my daughter, fear not; I will do to thee all that thou requirest: for all the city of my people doth know that thou art a virtuous woman.","ref":"Ruth 3:11","synthesized":"And now do not be afraid, my daughter. I will do for you whatever you request, since all my fellow townspeople know that you are a woman of noble character.","sources":{"KJV":{"text":"And now, my daughter, fear not; I will do to thee all that thou requirest: for all the city of my people doth know that thou art a virtuous woman."},"BSB":{"text":"And now do not be afraid, my daughter. I will do for you whatever you request, since all my fellow townspeople know that you are a woman of noble character."}},"definableWords":["daughter","woman"],"peopleInVerse":[]},"12":{"text":"And now it is true that I am thy near kinsman: howbeit there is a kinsman nearer than I.","ref":"Ruth 3:12","synthesized":"Yes, it is true that I am a kinsman-redeemer, but there is a redeemer nearer than I.","sources":{"KJV":{"text":"And now it is true that I am thy near kinsman: howbeit there is a kinsman nearer than I."},"BSB":{"text":"Yes, it is true that I am a kinsman-redeemer, but there is a redeemer nearer than I."}},"definableWords":["Redeemer"],"peopleInVerse":[]},"13":{"text":"Tarry this night, and it shall be in the morning, that if he will perform unto thee the part of a kinsman, well; let him do the kinsman’s part: but if he will not do the part of a kinsman to thee, then will I do the part of a kinsman to thee, as the LORD liveth: lie down until the morning.","ref":"Ruth 3:13","synthesized":"Stay here tonight, and in the morning, if he wants to redeem you, good. Let him redeem you. But if he does not want to redeem you, as surely as the LORD lives, I will. Now lie here until morning.”","sources":{"KJV":{"text":"Tarry this night, and it shall be in the morning, that if he will perform unto thee the part of a kinsman, well; let him do the kinsman’s part: but if he will not do the part of a kinsman to thee, then will I do the part of a kinsman to thee, as the LORD liveth: lie down until the morning."},"BSB":{"text":"Stay here tonight, and in the morning, if he wants to redeem you, good. Let him redeem you. But if he does not want to redeem you, as surely as the LORD lives, I will. Now lie here until morning.”"}},"definableWords":["good","LORD"],"peopleInVerse":[]},"14":{"text":"And she lay at his feet until the morning: and she rose up before one could know another. And he said, Let it not be known that a woman came into the floor.","ref":"Ruth 3:14","synthesized":"So she lay down at his feet until morning, but she got up before anyone else could recognize her.  Then Boaz said, “Do not let it be known that a woman came to the threshing floor.”","sources":{"KJV":{"text":"And she lay at his feet until the morning: and she rose up before one could know another. And he said, Let it not be known that a woman came into the floor."},"BSB":{"text":"So she lay down at his feet until morning, but she got up before anyone else could recognize her.  Then Boaz said, “Do not let it be known that a woman came to the threshing floor.”"}},"definableWords":["woman"],"peopleInVerse":["Boaz"]},"15":{"text":"Also he said, Bring the vail that thou hast upon thee, and hold it. And when she held it, he measured six measures of barley, and laid it on her: and she went into the city.","ref":"Ruth 3:15","synthesized":"And he told her, “Bring the shawl you are wearing and hold it out.” When she did so, he shoveled six measures of barley into her shawl. Then he went into the city.","sources":{"KJV":{"text":"Also he said, Bring the vail that thou hast upon thee, and hold it. And when she held it, he measured six measures of barley, and laid it on her: and she went into the city."},"BSB":{"text":"And he told her, “Bring the shawl you are wearing and hold it out.” When she did so, he shoveled six measures of barley into her shawl. Then he went into the city."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"And when she came to her mother in law, she said, Who art thou, my daughter? And she told her all that the man had done to her.","ref":"Ruth 3:16","synthesized":"When Ruth returned to her mother-in-law, Naomi asked her, “How did it go, my daughter?”  Then Ruth told her all that Boaz had done for her.","sources":{"KJV":{"text":"And when she came to her mother in law, she said, Who art thou, my daughter? And she told her all that the man had done to her."},"BSB":{"text":"When Ruth returned to her mother-in-law, Naomi asked her, “How did it go, my daughter?”  Then Ruth told her all that Boaz had done for her."}},"definableWords":["mother","law","daughter"],"peopleInVerse":["Ruth","Boaz"]},"17":{"text":"And she said, These six measures of barley gave he me; for he said to me, Go not empty unto thy mother in law.","ref":"Ruth 3:17","synthesized":"And she said, “He gave me these six measures of barley, for he said, ‘Do not go back to your mother-in-law empty-handed.’”","sources":{"KJV":{"text":"And she said, These six measures of barley gave he me; for he said to me, Go not empty unto thy mother in law."},"BSB":{"text":"And she said, “He gave me these six measures of barley, for he said, ‘Do not go back to your mother-in-law empty-handed.’”"}},"definableWords":["mother","law"],"peopleInVerse":[]},"18":{"text":"Then said she, Sit still, my daughter, until thou know how the matter will fall: for the man will not be in rest, until he have finished the thing this day.","ref":"Ruth 3:18","synthesized":"“Wait, my daughter,” said Naomi, “until you find out how things go, for he will not rest unless he has resolved the matter today.”","sources":{"KJV":{"text":"Then said she, Sit still, my daughter, until thou know how the matter will fall: for the man will not be in rest, until he have finished the thing this day."},"BSB":{"text":"“Wait, my daughter,” said Naomi, “until you find out how things go, for he will not rest unless he has resolved the matter today.”"}},"definableWords":["wait","daughter","rest"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"BOAZ REDEEMS RUTH","verses":{"1":{"text":"Then went Boaz up to the gate, and sat him down there: and, behold, the kinsman of whom Boaz spake came by; unto whom he said, Ho, such a one! turn aside, sit down here. And he turned aside, and sat down.","ref":"Ruth 4:1","synthesized":"Meanwhile, Boaz went to the gate and sat down there. Soon the kinsman-redeemer of whom he had spoken came along, and Boaz said, “Come over here, my friend, and sit down.” So he went over and sat down.","sources":{"KJV":{"text":"Then went Boaz up to the gate, and sat him down there: and, behold, the kinsman of whom Boaz spake came by; unto whom he said, Ho, such a one! turn aside, sit down here. And he turned aside, and sat down."},"BSB":{"text":"Meanwhile, Boaz went to the gate and sat down there. Soon the kinsman-redeemer of whom he had spoken came along, and Boaz said, “Come over here, my friend, and sit down.” So he went over and sat down."}},"definableWords":["Redeemer"],"peopleInVerse":["Boaz"]},"2":{"text":"And he took ten men of the elders of the city, and said, Sit ye down here. And they sat down.","ref":"Ruth 4:2","synthesized":"Then Boaz took ten of the elders of the city and said, “Sit here,” and they did so.","sources":{"KJV":{"text":"And he took ten men of the elders of the city, and said, Sit ye down here. And they sat down."},"BSB":{"text":"Then Boaz took ten of the elders of the city and said, “Sit here,” and they did so."}},"definableWords":[],"peopleInVerse":["Boaz"]},"3":{"text":"And he said unto the kinsman, Naomi, that is come again out of the country of Moab, selleth a parcel of land, which was our brother Elimelech’s:","ref":"Ruth 4:3","synthesized":"And he said to the kinsman-redeemer, “Naomi, who has returned from the land of Moab, is selling the piece of land that belonged to our brother Elimelech.","sources":{"KJV":{"text":"And he said unto the kinsman, Naomi, that is come again out of the country of Moab, selleth a parcel of land, which was our brother Elimelech’s:"},"BSB":{"text":"And he said to the kinsman-redeemer, “Naomi, who has returned from the land of Moab, is selling the piece of land that belonged to our brother Elimelech."}},"definableWords":["Redeemer","land","brother"],"peopleInVerse":[]},"4":{"text":"And I thought to advertise thee, saying, Buy it before the inhabitants, and before the elders of my people. If thou wilt redeem it, redeem it: but if thou wilt not redeem it, then tell me, that I may know: for there is none to redeem it beside thee; and I am after thee. And he said, I will redeem it.","ref":"Ruth 4:4","synthesized":"I thought I should inform you that you may buy it back in the presence of those seated here and in the presence of the elders of my people. If you want to redeem it, do so. But if you will not redeem it, tell me so I may know, because there is no one but you to redeem it, and I am next after you.”  “I will redeem it,” he replied.","sources":{"KJV":{"text":"And I thought to advertise thee, saying, Buy it before the inhabitants, and before the elders of my people. If thou wilt redeem it, redeem it: but if thou wilt not redeem it, then tell me, that I may know: for there is none to redeem it beside thee; and I am after thee. And he said, I will redeem it."},"BSB":{"text":"I thought I should inform you that you may buy it back in the presence of those seated here and in the presence of the elders of my people. If you want to redeem it, do so. But if you will not redeem it, tell me so I may know, because there is no one but you to redeem it, and I am next after you.”  “I will redeem it,” he replied."}},"definableWords":["people","one"],"peopleInVerse":[]},"5":{"text":"Then said Boaz, What day thou buyest the field of the hand of Naomi, thou must buy it also of Ruth the Moabitess, the wife of the dead, to raise up the name of the dead upon his inheritance.","ref":"Ruth 4:5","synthesized":"Then Boaz said, “On the day you buy the land from Naomi and also from Ruth the Moabitess, you must also acquire the widow of the deceased in order to raise up the name of the deceased on his inheritance.”","sources":{"KJV":{"text":"Then said Boaz, What day thou buyest the field of the hand of Naomi, thou must buy it also of Ruth the Moabitess, the wife of the dead, to raise up the name of the dead upon his inheritance."},"BSB":{"text":"Then Boaz said, “On the day you buy the land from Naomi and also from Ruth the Moabitess, you must also acquire the widow of the deceased in order to raise up the name of the deceased on his inheritance.”"}},"definableWords":["day","land","widow","name"],"peopleInVerse":["Boaz","Ruth"]},"6":{"text":"And the kinsman said, I cannot redeem it for myself, lest I mar mine own inheritance: redeem thou my right to thyself; for I cannot redeem it.","ref":"Ruth 4:6","synthesized":"The kinsman-redeemer replied, “I cannot redeem it myself, or I would jeopardize my own inheritance. Take my right of redemption, because I cannot redeem it.”","sources":{"KJV":{"text":"And the kinsman said, I cannot redeem it for myself, lest I mar mine own inheritance: redeem thou my right to thyself; for I cannot redeem it."},"BSB":{"text":"The kinsman-redeemer replied, “I cannot redeem it myself, or I would jeopardize my own inheritance. Take my right of redemption, because I cannot redeem it.”"}},"definableWords":["Redeemer","or","redemption"],"peopleInVerse":[]},"7":{"text":"Now this was the manner in former time in Israel concerning redeeming and concerning changing, for to confirm all things; a man plucked off his shoe, and gave it to his neighbour: and this was a testimony in Israel.","ref":"Ruth 4:7","synthesized":"Now in former times in Israel, concerning the redemption or exchange of property, to make any matter legally binding a man would remove his sandal and give it to the other party, and this was a confirmation in Israel.","sources":{"KJV":{"text":"Now this was the manner in former time in Israel concerning redeeming and concerning changing, for to confirm all things; a man plucked off his shoe, and gave it to his neighbour: and this was a testimony in Israel."},"BSB":{"text":"Now in former times in Israel, concerning the redemption or exchange of property, to make any matter legally binding a man would remove his sandal and give it to the other party, and this was a confirmation in Israel."}},"definableWords":["Israel","redemption","or","make","man"],"peopleInVerse":[]},"8":{"text":"Therefore the kinsman said unto Boaz, Buy it for thee. So he drew off his shoe.","ref":"Ruth 4:8","synthesized":"So the kinsman-redeemer removed his sandal and said to Boaz, “Buy it for yourself.”","sources":{"KJV":{"text":"Therefore the kinsman said unto Boaz, Buy it for thee. So he drew off his shoe."},"BSB":{"text":"So the kinsman-redeemer removed his sandal and said to Boaz, “Buy it for yourself.”"}},"definableWords":["Redeemer"],"peopleInVerse":["Boaz"]},"9":{"text":"And Boaz said unto the elders, and unto all the people, Ye are witnesses this day, that I have bought all that was Elimelech’s, and all that was Chilion’s and Mahlon’s, of the hand of Naomi.","ref":"Ruth 4:9","synthesized":"At this, Boaz said to the elders and all the people, “You are witnesses today that I am buying from Naomi all that belonged to Elimelech, Chilion, and Mahlon.","sources":{"KJV":{"text":"And Boaz said unto the elders, and unto all the people, Ye are witnesses this day, that I have bought all that was Elimelech’s, and all that was Chilion’s and Mahlon’s, of the hand of Naomi."},"BSB":{"text":"At this, Boaz said to the elders and all the people, “You are witnesses today that I am buying from Naomi all that belonged to Elimelech, Chilion, and Mahlon."}},"definableWords":["people"],"peopleInVerse":["Boaz"]},"10":{"text":"Moreover Ruth the Moabitess, the wife of Mahlon, have I purchased to be my wife, to raise up the name of the dead upon his inheritance, that the name of the dead be not cut off from among his brethren, and from the gate of his place: ye are witnesses this day.","ref":"Ruth 4:10","synthesized":"Moreover, I have acquired Ruth the Moabitess, Mahlon’s widow, as my wife, to raise up the name of the deceased through his inheritance, so that his name will not disappear from among his brothers or from the gate of his home. You are witnesses today.”","sources":{"KJV":{"text":"Moreover Ruth the Moabitess, the wife of Mahlon, have I purchased to be my wife, to raise up the name of the dead upon his inheritance, that the name of the dead be not cut off from among his brethren, and from the gate of his place: ye are witnesses this day."},"BSB":{"text":"Moreover, I have acquired Ruth the Moabitess, Mahlon’s widow, as my wife, to raise up the name of the deceased through his inheritance, so that his name will not disappear from among his brothers or from the gate of his home. You are witnesses today.”"}},"definableWords":["widow","wife","name","or"],"peopleInVerse":["Ruth"]},"11":{"text":"And all the people that were in the gate, and the elders, said, We are witnesses. The LORD make the woman that is come into thine house like Rachel and like Leah, which two did build the house of Israel: and do thou worthily in Ephratah, and be famous in Bethlehem:","ref":"Ruth 4:11","synthesized":"“We are witnesses,” said the elders and all the people at the gate. “May the LORD make the woman entering your home like Rachel and Leah, who together built up the house of Israel. May you be prosperous in Ephrathah and famous in Bethlehem.","sources":{"KJV":{"text":"And all the people that were in the gate, and the elders, said, We are witnesses. The LORD make the woman that is come into thine house like Rachel and like Leah, which two did build the house of Israel: and do thou worthily in Ephratah, and be famous in Bethlehem:"},"BSB":{"text":"“We are witnesses,” said the elders and all the people at the gate. “May the LORD make the woman entering your home like Rachel and Leah, who together built up the house of Israel. May you be prosperous in Ephrathah and famous in Bethlehem."}},"definableWords":["people","LORD","make","woman","Rachel","Leah","house","Israel"],"peopleInVerse":["Rachel","Leah"]},"12":{"text":"And let thy house be like the house of Pharez, whom Tamar bare unto Judah, of the seed which the LORD shall give thee of this young woman.","ref":"Ruth 4:12","synthesized":"And may your house become like the house of Perez, whom Tamar bore to Judah, because of the offspring the LORD will give you by this young woman.”","sources":{"KJV":{"text":"And let thy house be like the house of Pharez, whom Tamar bare unto Judah, of the seed which the LORD shall give thee of this young woman."},"BSB":{"text":"And may your house become like the house of Perez, whom Tamar bore to Judah, because of the offspring the LORD will give you by this young woman.”"}},"definableWords":["house","Tamar","Judah","LORD","woman"],"peopleInVerse":["Tamar"]},"13":{"text":"So Boaz took Ruth, and she was his wife: and when he went in unto her, the LORD gave her conception, and she bare a son.","ref":"Ruth 4:13","synthesized":"So Boaz took Ruth, and she became his wife. And when he had relations with her, the LORD enabled her to conceive, and she gave birth to a son.","sources":{"KJV":{"text":"So Boaz took Ruth, and she was his wife: and when he went in unto her, the LORD gave her conception, and she bare a son."},"BSB":{"text":"So Boaz took Ruth, and she became his wife. And when he had relations with her, the LORD enabled her to conceive, and she gave birth to a son."}},"definableWords":["wife","LORD","son"],"peopleInVerse":["Boaz","Ruth"]},"14":{"text":"And the women said unto Naomi, Blessed be the LORD, which hath not left thee this day without a kinsman, that his name may be famous in Israel.","ref":"Ruth 4:14","synthesized":"Then the women said to Naomi, “Blessed be the LORD, who has not left you this day without a kinsman-redeemer. May his name become famous in Israel.","sources":{"KJV":{"text":"And the women said unto Naomi, Blessed be the LORD, which hath not left thee this day without a kinsman, that his name may be famous in Israel."},"BSB":{"text":"Then the women said to Naomi, “Blessed be the LORD, who has not left you this day without a kinsman-redeemer. May his name become famous in Israel."}},"definableWords":["women","blessed","LORD","day","Redeemer","name","Israel"],"peopleInVerse":[]},"15":{"text":"And he shall be unto thee a restorer of thy life, and a nourisher of thine old age: for thy daughter in law, which loveth thee, which is better to thee than seven sons, hath born him.","ref":"Ruth 4:15","synthesized":"He will renew your life and sustain you in your old age. For your daughter-in-law, who loves you and is better to you than seven sons, has given him birth.”","sources":{"KJV":{"text":"And he shall be unto thee a restorer of thy life, and a nourisher of thine old age: for thy daughter in law, which loveth thee, which is better to thee than seven sons, hath born him."},"BSB":{"text":"He will renew your life and sustain you in your old age. For your daughter-in-law, who loves you and is better to you than seven sons, has given him birth.”"}},"definableWords":["life","daughter","law","sons"],"peopleInVerse":[]},"16":{"text":"And Naomi took the child, and laid it in her bosom, and became nurse unto it.","ref":"Ruth 4:16","synthesized":"And Naomi took the child, placed him on her lap, and became a nurse to him.","sources":{"KJV":{"text":"And Naomi took the child, and laid it in her bosom, and became nurse unto it."},"BSB":{"text":"And Naomi took the child, placed him on her lap, and became a nurse to him."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"And the women her neighbours gave it a name, saying, There is a son born to Naomi; and they called his name Obed: he is the father of Jesse, the father of David.","ref":"Ruth 4:17","synthesized":"The neighbor women said, “A son has been born to Naomi,” and they named him Obed. He became the father of Jesse, the father of David.","sources":{"KJV":{"text":"And the women her neighbours gave it a name, saying, There is a son born to Naomi; and they called his name Obed: he is the father of Jesse, the father of David."},"BSB":{"text":"The neighbor women said, “A son has been born to Naomi,” and they named him Obed. He became the father of Jesse, the father of David."}},"definableWords":["women","son","father","Father"],"peopleInVerse":["David"]},"18":{"text":"Now these are the generations of Pharez: Pharez begat Hezron,","ref":"Ruth 4:18","synthesized":"Now these are the generations of Perez:  Perez was the father of Hezron,","sources":{"KJV":{"text":"Now these are the generations of Pharez: Pharez begat Hezron,"},"BSB":{"text":"Now these are the generations of Perez:  Perez was the father of Hezron,"}},"definableWords":["father"],"peopleInVerse":[]},"19":{"text":"And Hezron begat Ram, and Ram begat Amminadab,","ref":"Ruth 4:19","synthesized":"Hezron was the father of Ram,   Ram was the father of Amminadab,","sources":{"KJV":{"text":"And Hezron begat Ram, and Ram begat Amminadab,"},"BSB":{"text":"Hezron was the father of Ram,   Ram was the father of Amminadab,"}},"definableWords":["father","Father"],"peopleInVerse":[]},"20":{"text":"And Amminadab begat Nahshon, and Nahshon begat Salmon,","ref":"Ruth 4:20","synthesized":"Amminadab was the father of Nahshon,   Nahshon was the father of Salmon,","sources":{"KJV":{"text":"And Amminadab begat Nahshon, and Nahshon begat Salmon,"},"BSB":{"text":"Amminadab was the father of Nahshon,   Nahshon was the father of Salmon,"}},"definableWords":["father","Father"],"peopleInVerse":[]},"21":{"text":"And Salmon begat Boaz, and Boaz begat Obed,","ref":"Ruth 4:21","synthesized":"Salmon was the father of Boaz,   Boaz was the father of Obed,","sources":{"KJV":{"text":"And Salmon begat Boaz, and Boaz begat Obed,"},"BSB":{"text":"Salmon was the father of Boaz,   Boaz was the father of Obed,"}},"definableWords":["father","Father"],"peopleInVerse":["Boaz"]},"22":{"text":"And Obed begat Jesse, and Jesse begat David.","ref":"Ruth 4:22","synthesized":"Obed was the father of Jesse,   and Jesse was the father of David.","sources":{"KJV":{"text":"And Obed begat Jesse, and Jesse begat David."},"BSB":{"text":"Obed was the father of Jesse,   and Jesse was the father of David."}},"definableWords":["father","Father"],"peopleInVerse":["David"]}}}};